// Parsing CSV line không allocation
void ParseCsvLine(ReadOnlySpan<char> line, Action<int, decimal, DateOnly> handler)
{
    int idx;
    // Field 1: ID
    idx = line.IndexOf(',');
    if (!int.TryParse(line[..idx], out int id)) return; // TryParse nhận Span trực tiếp
    line = line[(idx + 1)..]; // Slice — zero alloc

    // Field 2: Amount
    idx = line.IndexOf(',');
    if (!decimal.TryParse(line[..idx], out decimal amount)) return;
    line = line[(idx + 1)..];

    // Field 3: Date
    if (!DateOnly.TryParse(line, out DateOnly date)) return;

    handler(id, amount, date);
}

// stackalloc — buffer tạm trên stack
Span<char> FormatOrderKey(int orderId, ReadOnlySpan<char> prefix)
{
    Span<char> buffer = stackalloc char[32]; // stack, tự giải phóng khi method return
    prefix.CopyTo(buffer);
    orderId.TryFormat(buffer[prefix.Length..], out int written);
    return buffer[..(prefix.Length + written)];
}

// Chú ý: Span<char> trên stack KHÔNG thể escape phạm vi method
// → không return Span<char> từ method (compiler error)
// → không async method với stackalloc

// Với Span cần vượt scope: dùng ArrayPool hoặc Memory<T>
